import{_ as t,o as a,c as s,a2 as n}from"./chunks/framework.D36jym0Z.js";const h=JSON.parse('{"title":"Repository Structure","description":"","frontmatter":{},"headers":[],"relativePath":"development/repository-structure.md","filePath":"development/repository-structure.md","lastUpdated":1784629191000}'),p={name:"development/repository-structure.md"};function i(l,e,o,r,c,d){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="repository-structure" tabindex="-1">Repository Structure <a class="header-anchor" href="#repository-structure" aria-label="Permalink to &quot;Repository Structure&quot;">​</a></h1><p>The LightMem2 repository is organized around the plugin platform and its components.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>LightMem2/</span></span>
<span class="line"><span>├── components/</span></span>
<span class="line"><span>│   ├── packages/</span></span>
<span class="line"><span>│   │   ├── foundation/          # Shared contracts and infrastructure</span></span>
<span class="line"><span>│   │   │   ├── kernel/</span></span>
<span class="line"><span>│   │   │   ├── runtime-core/</span></span>
<span class="line"><span>│   │   │   ├── host-adapter/</span></span>
<span class="line"><span>│   │   │   ├── history/</span></span>
<span class="line"><span>│   │   │   ├── artifact-store/</span></span>
<span class="line"><span>│   │   │   └── product-surface/</span></span>
<span class="line"><span>│   │   └── features/            # Independently testable capabilities</span></span>
<span class="line"><span>│   │       ├── stabilizer/</span></span>
<span class="line"><span>│   │       ├── reduction/</span></span>
<span class="line"><span>│   │       ├── eviction/</span></span>
<span class="line"><span>│   │       └── memory/</span></span>
<span class="line"><span>│   ├── presets/</span></span>
<span class="line"><span>│   │   └── tokenpilot/          # Verified composition and host bindings</span></span>
<span class="line"><span>│   ├── adapters/                # Host-specific integration</span></span>
<span class="line"><span>│   │   ├── openclaw/            # OpenClaw native plugin adapter</span></span>
<span class="line"><span>│   │   ├── codex/               # Codex CLI proxy + hooks adapter</span></span>
<span class="line"><span>│   │   └── claude-code/         # Claude Code gateway adapter</span></span>
<span class="line"><span>│   └── products/</span></span>
<span class="line"><span>│       ├── cli/                 # Shared lightmem2 CLI and visual launcher</span></span>
<span class="line"><span>│       └── mcp/                 # Shared MCP recovery server</span></span>
<span class="line"><span>├── docs/                        # Public-facing notes and helpers</span></span>
<span class="line"><span>├── experiments/                 # Benchmark adapters and scripts</span></span>
<span class="line"><span>├── website/                     # This documentation site</span></span>
<span class="line"><span>├── figs/                        # Images for README</span></span>
<span class="line"><span>└── README.md</span></span></code></pre></div><h2 id="key-directories" tabindex="-1">Key Directories <a class="header-anchor" href="#key-directories" aria-label="Permalink to &quot;Key Directories&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Directory</th><th style="text-align:left;">Purpose</th></tr></thead><tbody><tr><td style="text-align:left;"><code>components/packages/foundation/kernel/</code></td><td style="text-align:left;">Types, interfaces, events — the contract layer</td></tr><tr><td style="text-align:left;"><code>components/packages/foundation/runtime-core/</code></td><td style="text-align:left;">Plugin execution engine</td></tr><tr><td style="text-align:left;"><code>components/packages/foundation/</code></td><td style="text-align:left;">Shared host, history, artifact, and product infrastructure</td></tr><tr><td style="text-align:left;"><code>components/packages/features/</code></td><td style="text-align:left;">Stabilizer, Reduction, Eviction, and Memory capabilities</td></tr><tr><td style="text-align:left;"><code>components/presets/tokenpilot/</code></td><td style="text-align:left;">TokenPilot policy and feature composition</td></tr><tr><td style="text-align:left;"><code>components/adapters/</code></td><td style="text-align:left;">One adapter per host</td></tr><tr><td style="text-align:left;"><code>components/products/cli/</code></td><td style="text-align:left;">The <code>lightmem2</code> CLI</td></tr><tr><td style="text-align:left;"><code>components/products/mcp/</code></td><td style="text-align:left;">Shared MCP server</td></tr></tbody></table><p>TokenPilot is a preset, not the owner of the shared packages. Each adapter binds the preset explicitly and declares the feature subset it supports:</p><ul><li>OpenClaw: Stabilizer, Reduction, and Eviction</li><li>Codex: Stabilizer and Reduction</li><li>Claude Code: Stabilizer and Reduction</li></ul><p>CLI and Visual host discovery use adapter-provided product registrations. The MCP recovery server declares its TokenPilot preset ownership separately because it is host-neutral.</p><h2 id="workspace" tabindex="-1">Workspace <a class="header-anchor" href="#workspace" aria-label="Permalink to &quot;Workspace&quot;">​</a></h2><p>The repository uses pnpm workspaces. See <code>pnpm-workspace.yaml</code> for the full list.</p><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li><a href="/LightMem2/development/local-development">Local Development</a></li><li><a href="/LightMem2/development/build-and-test">Build and Test</a></li><li><a href="/LightMem2/development/contributing">Contributing</a></li></ul>`,12)])])}const m=t(p,[["render",i]]);export{h as __pageData,m as default};
